import base64
import json
from datetime import datetime
from typing import Final, cast

from aws_lambda_powertools import Logger
from aws_lambda_powertools.tracing import Tracer
from aws_lambda_powertools.utilities.typing import LambdaContext
from botocore.exceptions import ClientError
from dotenv import load_dotenv

from dns_de_rte_orchestrator.audit_logging import AuditLogger, get_audit_logger
from dns_de_rte_orchestrator.dryrun import is_dry_run
from dns_de_rte_orchestrator.erasure_request import (
    VALID_DETAIL_KEYS,
    ErasureDetailKey,
    ErasureRequest,
)

from .request_repository import RequestRepository, get_request_repository

# Load .env file, mostly useful for testing
_ = load_dotenv()

logger = Logger()
tracer = Tracer()  # Sets service via POWERTOOLS_SERVICE_NAME env var

in_dry_run_mode: Final[bool] = is_dry_run()
request_repo: RequestRepository = get_request_repository()
audit: AuditLogger = get_audit_logger()


class InvalidRequestError(ValueError):
    pass


_MAX_FIELD_LEN = 512


def _require_str(body: dict[str, object], key: str) -> str:
    v = body[key]
    if not isinstance(v, str) or not v:
        raise InvalidRequestError(f"Field '{key}' must be a non-empty string")
    if len(v) > _MAX_FIELD_LEN:
        raise InvalidRequestError(
            f"Field '{key}' must be <= {_MAX_FIELD_LEN} characters"
        )
    return v


def request_from_event(
    event: dict[str, object],
) -> ErasureRequest:
    """Convert the input event into an ErasureRequest"""
    try:
        raw_body: str = cast(str, event.get("body") or "")
        if event.get("isBase64Encoded"):
            raw_body = base64.b64decode(raw_body).decode("utf-8")
        body: dict[str, object] = cast(dict[str, object], json.loads(raw_body))
    except (json.JSONDecodeError, ValueError) as e:
        raise InvalidRequestError(f"Invalid JSON body: {e}") from e

    required_fields = ("id", "source", "date_issued", "erasure_details")
    missing = [f for f in required_fields if f not in body]
    if missing:
        raise InvalidRequestError(f"Missing required fields: {', '.join(missing)}")

    state_raw = body.get("state", "new")
    if not isinstance(state_raw, str):
        raise InvalidRequestError("Field 'state' must be a string")
    if state_raw != "new":
        raise InvalidRequestError(
            f"Erasure requests must be created in state 'new', got '{state_raw}'"
        )

    date_issued_raw = body["date_issued"]
    if not isinstance(date_issued_raw, str):
        raise InvalidRequestError("Field 'date_issued' must be a string")
    try:
        date_issued = datetime.fromisoformat(date_issued_raw)
    except ValueError as e:
        raise InvalidRequestError(f"Invalid date_issued: {e}") from e

    id_ = _require_str(body, "id")
    source = _require_str(body, "source")

    erasure_details_raw = body["erasure_details"]
    if not isinstance(erasure_details_raw, dict):
        raise InvalidRequestError("erasure_details must be an object")
    erasure_details: dict[ErasureDetailKey, str] = {}
    for k, v in cast(dict[str, object], erasure_details_raw).items():
        if k not in VALID_DETAIL_KEYS:
            raise InvalidRequestError(f"Unknown erasure_details key: '{k}'")
        if not isinstance(v, str) or not v:
            raise InvalidRequestError(
                f"erasure_details['{k}'] must be a non-empty string"
            )
        erasure_details[k] = v  # type: ignore[literal-required]

    site_ids: list[int] = []
    if "site_ids" in body:
        if body["site_ids"] is not None:
            if not isinstance(body["site_ids"], list):
                raise InvalidRequestError("site_ids must be a list")
            site_ids_list = cast(list[object], body["site_ids"])
            for item in site_ids_list:
                if type(item) is not int:
                    raise InvalidRequestError("site_ids entries must be integers")
                site_ids.append(item)

    return ErasureRequest(
        id=id_,
        source=source,
        state=state_raw,
        date_issued=date_issued,
        erasure_details=erasure_details,
        site_ids=site_ids,
    )


def _response(
    status_code: int,
    body: dict[str, str | int],
) -> dict[str, object]:
    return {
        "statusCode": status_code,
        "headers": {"Content-Type": "application/json"},
        "body": json.dumps(body),
    }


@tracer.capture_lambda_handler
@logger.inject_lambda_context
def lambda_handler(
    event: dict[str, object],
    _context: LambdaContext,
) -> dict[str, object]:
    """
    Entrypoint for AWS Lambda that does item creation.

    This should be very simple, the Lambda should simply create an entry in the
    underlying storage, another lambda or piece of compute will process them.
    """
    try:
        request: ErasureRequest = request_from_event(event)
    except (InvalidRequestError, json.JSONDecodeError) as e:
        logger.warning("Rejecting erasure request with invalid body: %s", str(e))
        return _response(400, {"error": "invalid request body"})

    try:
        if in_dry_run_mode:
            logger.warning("DryRun: Would have created request for %s", request.id)
        else:
            request_repo.create(request)
    except ClientError as e:
        if e.response.get("Error", {}).get("Code") == "ConditionalCheckFailedException":
            logger.warning("Duplicate erasure request rejected: %s", request.id)
            return _response(409, {"error": "conflict", "id": request.id})
        logger.exception("Failed to create erasure request %s", str(request))
        return _response(500, {"error": "internal error"})
    except Exception:
        logger.exception("Failed to create erasure request %s", str(request))
        return _response(500, {"error": "internal error"})

    audit.log(request.id, "Erasure request was created")
    return _response(200, {"id": request.id})

import os
from abc import ABC, abstractmethod
from collections.abc import Mapping, Sequence
from datetime import datetime
from typing import TYPE_CHECKING, Any, Literal, cast, override

import boto3

if TYPE_CHECKING:
    from types_boto3_dynamodb.client import DynamoDBClient
    from types_boto3_dynamodb.type_defs import (
        AttributeValueTypeDef,
        UniversalAttributeValueTypeDef,
    )
else:
    DynamoDBClient = Any
    AttributeValueTypeDef = dict[str, Any]
    UniversalAttributeValueTypeDef = dict[str, Any]


from dns_de_rte_orchestrator.erasure_request import ErasureRequest, ErasureState


class RequestRepository(ABC):
    """Common interface for dealing with Erasure Request storage"""

    @abstractmethod
    def create(self, request: ErasureRequest) -> None:
        """Create a new erasure request in the underlying storage"""
        raise NotImplementedError()

    @abstractmethod
    def update(self, request: ErasureRequest) -> None:
        """
        Updates an existing item in the underlying storage based on the given request.

        Note that the requests id is used to do the updating.
        """
        raise NotImplementedError()

    @abstractmethod
    def get(self, id: str) -> ErasureRequest | None:
        """Get a specific request from the underlying storage based upon its id."""
        raise NotImplementedError()

    @abstractmethod
    def get_all_in_state(
        self,
        state: ErasureState,
        limit: int = 100,
        from_date: datetime | None = None,
    ) -> list[ErasureRequest]:
        """
        Get the erasure requests within a given state up to a certain limit.

        When the limit is reached, that many items are returned. There could be
        more items with the given state.

        You can optionally set a from_date to filter only results from that
        given time and date until now.

        Warning: This can return a lot of results if you use a terminal state.

        Warning: Implementations may cap the amount of items returned under the
        given limit if certain conditions are met. For example, DynamoDB will
        stop returning items for a single query if the total size reaches 1 MB.
        It is up to implementations as to how much they respect this limit.
        For example, a DynamoDB implementation could paginate.

        """
        raise NotImplementedError()


class InMemoryRequestRepository(RequestRepository):
    """
    An example implementation of a request repository.

    This implementation simply stores objects in an internal dictionary.
    It does not clone objects.

    This implementation is not thread safe.
    """

    def __init__(self) -> None:
        super().__init__()
        self._db: dict[str, ErasureRequest] = {}

    @override
    def create(self, request: ErasureRequest) -> None:
        if request.id in self._db:
            raise ValueError(f"{request.id} already exists")
        self._db[request.id] = request

    @override
    def update(self, request: ErasureRequest) -> None:
        if request.id not in self._db:
            raise ValueError(f"{request.id} does not already exists")
        self._db[request.id] = request

    @override
    def get(self, id: str) -> ErasureRequest | None:
        return self._db.get(id)

    @override
    def get_all_in_state(
        self, state: ErasureState, limit: int = 100, from_date: datetime | None = None
    ) -> list[ErasureRequest]:
        if limit <= 0:
            return []
        found: list[ErasureRequest] = []
        count: int = 0
        for _, item in self._db.items():
            if item.state == state:
                if from_date is not None and item.date_issued < from_date:
                    continue
                found.append(item)
                count += 1
                if count >= limit:
                    break
        return found


class DynamoDBRequestRepository(RequestRepository):
    """DynamoDB backed repository implementation"""

    ID_FIELD: Literal["id"] = "id"
    STATE_FIELD: Literal["state"] = "state"
    DATE_ISSUED_FIELD: Literal["date_issued"] = "date_issued"
    SOURCE_FIELD: Literal["source"] = "source"
    ERASURE_DETAILS_FIELD: Literal["erasure_details"] = "erasure_details"
    SITE_IDS_FIELD: Literal["site_ids"] = "site_ids"

    NOT_EXISTS_CONDITION: str = f"attribute_not_exists({ID_FIELD})"
    EXISTS_CONDITION: str = f"attribute_exists({ID_FIELD})"

    def __init__(
        self, table_name: str, index_name: str, dynamodb: DynamoDBClient
    ) -> None:
        super().__init__()
        self.table_name: str = table_name
        self.index_name: str = index_name
        self.dynamodb: DynamoDBClient = dynamodb

    @override
    def create(self, request: ErasureRequest) -> None:
        item = self.item_from_request(request)
        # This should error if there is an item in the table with the given id
        _response = self.dynamodb.put_item(
            TableName=self.table_name,
            Item=item,
            ReturnValues="NONE",
            ConditionExpression=self.NOT_EXISTS_CONDITION,
        )

    @override
    def update(self, request: ErasureRequest) -> None:
        item = self.item_from_request(request)
        # This should error if there is NOT an item in the table with the given
        # id
        _response = self.dynamodb.put_item(
            TableName=self.table_name,
            Item=item,
            ReturnValues="NONE",
            ConditionExpression=self.EXISTS_CONDITION,
        )

    @override
    def get(self, id: str) -> ErasureRequest | None:
        response = self.dynamodb.get_item(
            TableName=self.table_name, Key={self.ID_FIELD: {"S": id}}
        )

        if "Item" in response:
            item: dict[str, AttributeValueTypeDef] = response["Item"]
            # Convert the item back to a domain object
            return self.response_to_request(item)
        else:
            return None

    @override
    def get_all_in_state(
        self,
        state: ErasureState,
        limit: int = 100,
        from_date: datetime | None = None,
    ) -> list[ErasureRequest]:
        if limit <= 0:
            return []
        key_condition: str = "#S = :state"

        #  The attribute values being used in the query
        attribute_values: Mapping[str, UniversalAttributeValueTypeDef] = {
            ":state": {"S": state}
        }
        # Replacements for attribute names that are reserved keywords
        attribute_names: Mapping[str, str] = {"#S": "state"}

        if from_date is not None:
            # Add on the sort key condition to the key_condition
            key_condition += " AND date_issued >= :date"
            # Add the sort key value to attribute_values
            timestamp = int(from_date.timestamp() * 1000)
            attribute_values[":date"] = {"N": str(timestamp)}

        paginator = self.dynamodb.get_paginator("query")
        pages = paginator.paginate(
            TableName=self.table_name,
            IndexName=self.index_name,
            Select="ALL_ATTRIBUTES",
            ScanIndexForward=True,  # explicitly set direction of scan
            KeyConditionExpression=key_condition,
            ExpressionAttributeNames=attribute_names,
            ExpressionAttributeValues=attribute_values,
            PaginationConfig={"PageSize": min([100, limit]), "MaxItems": limit},
        )

        results: list[ErasureRequest] = []
        for page in pages:
            # iterate pages and add converted results to list
            if "Items" not in page:
                continue
            for item in page["Items"]:
                erasure = self.response_to_request(item)
                results.append(erasure)

        return results

    @classmethod
    def response_to_request(
        cls, response: dict[str, AttributeValueTypeDef]
    ) -> ErasureRequest:
        """Convert a response dictionary to an ErasureRequest"""
        if cls.ID_FIELD not in response:
            raise ValueError(f"Missing {cls.ID_FIELD} field")
        if cls.STATE_FIELD not in response:
            raise ValueError(f"Missing {cls.STATE_FIELD} field")
        if cls.DATE_ISSUED_FIELD not in response:
            raise ValueError(f"Missing {cls.DATE_ISSUED_FIELD} field")
        if cls.SOURCE_FIELD not in response:
            raise ValueError(f"Missing {cls.SOURCE_FIELD} field")

        id: str = response[cls.ID_FIELD][
            "S"
        ]  # pyright: ignore[reportTypedDictNotRequiredAccess]
        state: str = response[cls.STATE_FIELD][
            "S"
        ]  # pyright: ignore[reportTypedDictNotRequiredAccess]
        source: str = response[cls.SOURCE_FIELD][
            "S"
        ]  # pyright: ignore[reportTypedDictNotRequiredAccess]

        date_issued_field = response[cls.DATE_ISSUED_FIELD]
        if "N" not in date_issued_field:
            raise ValueError(f"Wrong type for {cls.DATE_ISSUED_FIELD}")
        date_issued_ms = int(date_issued_field["N"])
        date_issued: datetime = datetime.fromtimestamp(date_issued_ms / 1000)

        erasure_details: dict[str, str] = {}
        if cls.ERASURE_DETAILS_FIELD in response:
            erasure_details_field = response[cls.ERASURE_DETAILS_FIELD]
            if "M" in erasure_details_field:
                returned_map = erasure_details_field["M"]
                for k, v in returned_map.items():  # pyright: ignore[reportAny]
                    coerced = cast(dict[str, str], v)
                    value: str = coerced["S"]
                    erasure_details[k] = value

        site_ids: list[int] = []
        if cls.SITE_IDS_FIELD in response:
            site_ids_field = response[cls.SITE_IDS_FIELD]
            if "L" in site_ids_field:
                returned_list: Sequence[AttributeValueTypeDef] = site_ids_field["L"]
                for item in returned_list:
                    if "N" in item:
                        site_id = int(item["N"])
                        site_ids.append(site_id)
                    else:
                        raise ValueError(
                            f"Wrong type inside {cls.SITE_IDS_FIELD} list: {item}"
                        )

        # TODO: Should we validate the fields afterward?
        return ErasureRequest(
            id=id,
            state=state,  # pyright: ignore[reportArgumentType]
            date_issued=date_issued,
            source=source,
            erasure_details=erasure_details,  # pyright: ignore[reportArgumentType],
            site_ids=site_ids,
        )

    @classmethod
    def item_from_request(cls, request: ErasureRequest):
        """Convert a request to a DynamoDB Item"""
        # Build the map type
        erasure_details: dict[str, dict[str, str]] = {}
        for k, v in request.erasure_details.items():
            erasure_details[k] = {"S": v}

        item: dict[
            str, dict[str, str | dict[str, dict[str, str]] | list[dict[str, str]]]
        ] = {
            cls.ID_FIELD: {"S": request.id},
            cls.STATE_FIELD: {"S": request.state.strip().lower()},
            cls.DATE_ISSUED_FIELD: {"N": str(request.date_issued_ms)},
            cls.SOURCE_FIELD: {"S": request.source},
            cls.ERASURE_DETAILS_FIELD: {"M": erasure_details},
        }
        if len(request.site_ids) > 0:
