"""
Environment variable used for defining the DynamoDB index used when creating
from the environment.

When testing this variable should not be favoured, instead you should set the
index name explicitly.
"""


def get_dyanmodb_request_repository() -> DynamoDBRequestRepository:
    """Return a DynamoDB request repository from using environment variables"""

    table_name: str | None = os.getenv(DYNAMO_DB_TABLE_ENV_VAR)
    if table_name is None or table_name == "":
        raise ValueError(f"{DYNAMO_DB_TABLE_ENV_VAR} was not set")

    index_name: str | None = os.getenv(DYNAMO_DB_INDEX_ENV_VAR)
    if index_name is None or index_name == "":
        raise ValueError(f"{DYNAMO_DB_INDEX_ENV_VAR} was not set")

    dynamodb: DynamoDBClient = boto3.client("dynamodb")
    return DynamoDBRequestRepository(
        table_name=table_name, index_name=index_name, dynamodb=dynamodb
    )


REPOSITORY_TYPE_ENV_VAR: Literal["REPOSITORY_TYPE"] = "REPOSITORY_TYPE"
"""The environment variable used to force a specific repository type"""


def get_request_repository() -> RequestRepository:
    """Get a concrete repository via the environment variables"""
    repo_type: str | None = os.getenv(REPOSITORY_TYPE_ENV_VAR)

    match repo_type:
        case "" | None:
            return _get_default_request_repository()
        case s:
            match s.strip().lower():
                case "dynamodb":
                    return get_dyanmodb_request_repository()
                case "memory":
                    return InMemoryRequestRepository()
                case "":
                    return _get_default_request_repository()
                case _:
                    raise ValueError(f"Unknown {REPOSITORY_TYPE_ENV_VAR} entry: {s}")


def _get_default_request_repository() -> RequestRepository:
    """Return a default request repository, this is currently DynamoDB"""
    return get_dyanmodb_request_repository()

